"""Generate massive history/politics/society knowledge base for Brain19."""
import json

concepts = []
relations = []

def c(label, definition, cat="FACT", tv=0.99, tags=None):
    concepts.append({"label": label, "definition": definition, "trust_category": cat, "trust_value": tv, "tags": tags or []})

def r(src, tgt, rel, w=0.92):
    relations.append({"source_label": src, "target_label": tgt, "relation_type": rel, "weight": w})

